import React from "react";
import { Link, useLocation } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { RootStore } from "../../utils/TypeScript";
import { logout } from "../../redux/actions/authAction";

const Menu = () => {
  const { auth } = useSelector((state: RootStore) => state);
  const dispatch = useDispatch();

  const { pathname } = useLocation();

  const bfLoginLinks = [
    { label: "ໜ້າຫຼັກ", path: "/" },
    { label: "ເຂົ້າສູ່ລະບົບ", path: "/login" },
    { label: "ສະມັກສະມາຊິກ", path: "/register" },
  ];

  const afLoginLinks = [
    { label: "ໜ້າຫຼັກ", path: "/" },
    { label: "ເພີ້ມພຣະສູດ", path: "/create_blog" },
  ];

  const navLinks = auth.access_token ? afLoginLinks : bfLoginLinks;

  const isActive = (pn: string) => {
    if (pn === pathname) return "active";
  };

  const handleLogout = () => {
    if (!auth.access_token) return;
    dispatch(logout(auth.access_token));
  };

  return (
    <ul
      className="navbar-nav ms-auto"
      style={{ backgroundColor: "#FEF7EC", color: "#583804" }}
    >
      {navLinks.map((link, index) => (
        <li
          key={index}
          className={`nav-item ${isActive(link.path)}`}
          style={{ color: "#583804" }}
        >
          <Link
            className="nav-link"
            to={link.path}
            style={{ color: "#583804" }}
          >
            {link.label}
          </Link>
        </li>
      ))}

      {auth.user?.role === "admin" && (
        <li
          className={`nav-item ${isActive("/category")}`}
          style={{ color: "#583804" }}
        >
          <Link
            to="/category"
            className="nav-link"
            style={{ color: "#583804" }}
          >
            ໝວດທັມ
          </Link>
        </li>
      )}

      {auth.user && (
        <li className="nav-item dropdown">
          <span
            className="nav-link dropdown-toggle"
            id="navbarDropdown"
            role="button"
            data-bs-toggle="dropdown"
            aria-expanded="false"
          >
            <img src={auth.user.avatar} alt="avatar" className="avatar" />
          </span>

          <ul className="dropdown-menu" aria-labelledby="navbarDropdown">
            <li>
              <Link className="dropdown-item" to={`/profile/${auth.user._id}`}>
                ຂໍ້ມູນສະມາຊິກ
              </Link>
            </li>

            <li>
              <hr className="dropdown-divider" />
            </li>

            <li>
              <Link className="dropdown-item" to="/" onClick={handleLogout}>
                ອອກຈາກລະບົບ
              </Link>
            </li>
          </ul>
        </li>
      )}
    </ul>
  );
};

export default Menu;
